import React, { useState, useEffect } from 'react';
import {
  LineChart, Line, XAxis, YAxis, Tooltip,
  ResponsiveContainer, PieChart, Pie, Cell, BarChart, Bar, Legend
} from 'recharts';
import api, { formatCurrency, formatDate, statusLabel } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

const COLORS = ['#6c63ff','#43e97b','#f7971e','#ff6b6b','#38b2ff','#a78bfa','#ffd93d'];

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const { addToast } = useToast();

  useEffect(() => {
    api.get('/reports/dashboard')
      .then(res => setData(res.data))
      .catch(() => addToast('Không thể tải dashboard', 'error'))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading"><div className="spinner" /></div>;
  if (!data) return null;

  const revenueData = data.revenueByDay.map(d => ({
    date: new Date(d.date).toLocaleDateString('vi-VN', { month: '2-digit', day: '2-digit' }),
    'Doanh thu (triệu)': +(Number(d.revenue) / 1e6).toFixed(2),
  }));

  const statusData = data.statusBreakdown.map(s => ({
    name: statusLabel[s.status] || s.status,
    value: Number(s.count),
  }));

  return (
    <div className="page">
      <div className="page-header">
        <h1>📈 Dashboard</h1>
        <p>Tổng quan hoạt động toàn hệ thống</p>
      </div>

      <div className="stats-grid">
        <div className="stat-card purple">
          <div className="stat-icon">💰</div>
          <div className="stat-label">Tổng doanh thu</div>
          <div className="stat-value" style={{ fontSize: 20 }}>{formatCurrency(data.stats.totalRevenue)}</div>
        </div>
        <div className="stat-card green">
          <div className="stat-icon">📋</div>
          <div className="stat-label">Tổng đơn hàng</div>
          <div className="stat-value">{data.stats.totalOrders}</div>
        </div>
        <div className="stat-card blue">
          <div className="stat-icon">👥</div>
          <div className="stat-label">Khách hàng</div>
          <div className="stat-value">{data.stats.totalCustomers}</div>
        </div>
        <div className="stat-card orange">
          <div className="stat-icon">⏳</div>
          <div className="stat-label">Đơn đang xử lý</div>
          <div className="stat-value">{data.stats.pendingOrders}</div>
        </div>
        <div className="stat-card red">
          <div className="stat-icon">⚠️</div>
          <div className="stat-label">SP sắp hết hàng</div>
          <div className="stat-value">{data.stats.lowStockItems}</div>
        </div>
      </div>

      <div className="grid-2" style={{ marginBottom: 24 }}>
        <div className="card">
          <div className="card-title">Doanh thu 30 ngày (triệu VNĐ)</div>
          {revenueData.length === 0 ? (
            <div style={{ color: 'var(--text-muted)', fontSize: 13, padding: '20px 0', textAlign: 'center' }}>
              Chưa có dữ liệu thanh toán
            </div>
          ) : (
            <ResponsiveContainer width="100%" height={220}>
              <LineChart data={revenueData}>
                <XAxis dataKey="date" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} />
                <Tooltip
                  contentStyle={{ background: 'var(--bg-card2)', border: '1px solid var(--border)', borderRadius: 8, color: 'var(--text)' }}
                  formatter={v => [v + ' triệu', 'Doanh thu']}
                />
                <Line type="monotone" dataKey="Doanh thu (triệu)" stroke="var(--accent)" strokeWidth={2.5} dot={false} />
              </LineChart>
            </ResponsiveContainer>
          )}
        </div>

        <div className="card">
          <div className="card-title">Phân bố trạng thái đơn hàng</div>
          {statusData.length === 0 ? (
            <div style={{ color: 'var(--text-muted)', fontSize: 13, padding: '20px 0', textAlign: 'center' }}>Chưa có dữ liệu</div>
          ) : (
            <ResponsiveContainer width="100%" height={220}>
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%" cy="50%"
                  outerRadius={80}
                  dataKey="value"
                  label={({ name, value }) => `${name}: ${value}`}
                  labelLine={true}
                >
                  {statusData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                </Pie>
                <Tooltip contentStyle={{ background: 'var(--bg-card2)', border: '1px solid var(--border)', borderRadius: 8 }} />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      <div className="card">
        <div className="card-title">Đơn hàng gần đây</div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Mã đơn</th>
                <th>Khách hàng</th>
                <th>Trạng thái</th>
                <th>Giá trị</th>
                <th>Ngày đặt</th>
              </tr>
            </thead>
            <tbody>
              {data.recentOrders.map(o => (
                <tr key={o.orderID}>
                  <td style={{ fontFamily: 'Syne', fontWeight: 700 }}>#{o.orderID}</td>
                  <td>{o.customerName}</td>
                  <td><span className={`badge badge-${o.status}`}>{statusLabel[o.status]}</span></td>
                  <td style={{ fontFamily: 'Syne', fontWeight: 700, color: 'var(--accent)' }}>{formatCurrency(o.totalAmount)}</td>
                  <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{formatDate(o.orderDate)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
